import React, { useState, useEffect } from "react";
import api from "../api/api"; // ✅ Usamos tu instancia personalizada con el token
import "bootstrap/dist/css/bootstrap.min.css";
import TicketVenta from "../components/TicketVenta";
import { FaSearch, FaCartPlus, FaCashRegister, FaUser } from "react-icons/fa";

export default function Ventas() {
  const [productos, setProductos] = useState([]);
  const [clientes, setClientes] = useState([]);
  const [busquedaProducto, setBusquedaProducto] = useState("");
  const [productoSeleccionado, setProductoSeleccionado] = useState(null);
  const [clienteNombre, setClienteNombre] = useState("");
  const [clienteApellido, setClienteApellido] = useState("");
  const [clienteTelefono, setClienteTelefono] = useState("");
  const [cantidad, setCantidad] = useState(1);
  const [mensaje, setMensaje] = useState("");
  const [ticket, setTicket] = useState(null);
  const [carrito, setCarrito] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    obtenerProductos();
    obtenerClientes();
  }, []);

  const obtenerProductos = async () => {
    try {
      const res = await api.get("/productos");
      setProductos(res.data);
    } catch (err) {
      console.error("❌ Error al obtener productos:", err);
    }
  };

  const obtenerClientes = async () => {
    try {
      const res = await api.get("/clientes");
      setClientes(res.data);
    } catch (err) {
      console.error("❌ Error al obtener clientes:", err);
    }
  };

  const buscarProducto = (texto) => {
    setBusquedaProducto(texto);
    const producto = productos.find((p) =>
      (p.nombre || "").toLowerCase().includes(texto.toLowerCase())
    );
    setProductoSeleccionado(producto || null);
    setMensaje("");
  };

  const agregarAlCarrito = () => {
    if (!productoSeleccionado || cantidad <= 0) return;

    const stockActual = Number(productoSeleccionado.stock || 0);
    const prodID = productoSeleccionado._id;
    const precioUnitario = Number(productoSeleccionado.precio);
    const nombreProd = productoSeleccionado.nombre;

    if (stockActual < cantidad) {
      setMensaje(`❌ Stock insuficiente. Disponible: ${stockActual}`);
      return;
    }

    const existente = carrito.find((p) => p.producto_id === prodID);

    if (existente) {
      if (existente.cantidad + cantidad > stockActual) {
        setMensaje("❌ No puedes agregar más de lo disponible");
        return;
      }
      setCarrito(
        carrito.map((p) =>
          p.producto_id === prodID
            ? { ...p, cantidad: p.cantidad + cantidad }
            : p
        )
      );
    } else {
      setCarrito([
        ...carrito,
        {
          producto_id: prodID, // ✅ Nombre estándar para MongoDB
          nombre: nombreProd,
          cantidad: cantidad,
          precio: precioUnitario,
        },
      ]);
    }

    setProductoSeleccionado(null);
    setBusquedaProducto("");
    setCantidad(1);
    setMensaje("✅ Producto añadido");
    setTimeout(() => setMensaje(""), 1500);
  };

  const calcularSubtotal = () =>
    carrito.reduce((acc, p) => acc + p.cantidad * p.precio, 0);

  const realizarVenta = async () => {
    if (!clienteNombre.trim() || !clienteApellido.trim()) {
      setMensaje("⚠️ Ingresa nombre y apellido del cliente.");
      return;
    }

    setLoading(true);
    try {
      let clienteExistente = clientes.find(
        (c) =>
          (c.nombre || "").toLowerCase() === clienteNombre.toLowerCase() &&
          (c.apellido || "").toLowerCase() === clienteApellido.toLowerCase()
      );

      const subtotal = calcularSubtotal();
      const iva = subtotal * 0.13;
      const total = subtotal + iva;

      // ✅ PAYLOAD CORREGIDO: Estos nombres deben coincidir con tu Schema de MongoDB
      const payload = {
        cliente_id: clienteExistente?._id || null, 
        nombre_cliente: `${clienteNombre} ${clienteApellido}`,
        telefono_cliente: clienteTelefono || "",
        productos: carrito.map((p) => ({
          producto_id: p.producto_id,
          cantidad: p.cantidad,
          precio: p.precio
        })),
        subtotal: subtotal,
        iva: iva,
        total: total
      };

      const res = await api.post("/ventas", payload); // ✅ Usamos la ruta /ventas

      setTicket(res.data.venta || res.data); 
      setMensaje("✅ Venta realizada con éxito.");
      setCarrito([]);
      setClienteNombre("");
      setClienteApellido("");
      setClienteTelefono("");
      
      // Actualizar datos locales
      obtenerProductos();
      obtenerClientes();
      
    } catch (err) {
      const msgError = err.response?.data?.mensaje || err.message;
      setMensaje(`❌ Error: ${msgError}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container-fluid p-4 bg-light min-vh-100">
      <div className="d-flex align-items-center mb-4">
        <FaCashRegister className="fs-2 text-primary me-3" />
        <h2 className="fw-bold mb-0">Punto de Venta (POS)</h2>
      </div>

      <div className="row">
        {/* PANEL IZQUIERDO */}
        <div className="col-lg-7">
          <div className="card shadow-sm border-0 p-4 mb-4 rounded-4">
            <h5 className="fw-bold mb-3 text-secondary"><FaSearch className="me-2" /> 1. Buscar Productos</h5>
            <div className="input-group mb-3">
              <span className="input-group-text bg-white border-0 shadow-sm"><FaSearch className="text-muted" /></span>
              <input
                type="text"
                className="form-control border-0 shadow-sm"
                placeholder="Escriba el nombre..."
                value={busquedaProducto}
                onChange={(e) => buscarProducto(e.target.value)}
              />
            </div>

            {productoSeleccionado && (
              <div className="card bg-primary text-white border-0 shadow p-3 mb-4">
                <div className="d-flex justify-content-between align-items-center">
                  <div>
                    <h5 className="mb-0 fw-bold">{productoSeleccionado.nombre}</h5>
                    <p className="mb-0 small">Stock: {productoSeleccionado.stock} | ${productoSeleccionado.precio}</p>
                  </div>
                  <div className="d-flex gap-2">
                    <input type="number" className="form-control form-control-sm w-25 text-center" value={cantidad} onChange={(e) => setCantidad(Number(e.target.value))} min="1" />
                    <button className="btn btn-light btn-sm fw-bold" onClick={agregarAlCarrito}>+ Agregar</button>
                  </div>
                </div>
              </div>
            )}

            <h5 className="fw-bold mb-3 mt-2 text-secondary"><FaUser className="me-2" /> 2. Datos del Cliente</h5>
            <div className="row g-3">
              <div className="col-md-6"><input className="form-control border-0 shadow-sm" placeholder="Nombre" value={clienteNombre} onChange={(e) => setClienteNombre(e.target.value)} /></div>
              <div className="col-md-6"><input className="form-control border-0 shadow-sm" placeholder="Apellido" value={clienteApellido} onChange={(e) => setClienteApellido(e.target.value)} /></div>
            </div>

            {mensaje && (
              <div className={`alert mt-4 border-0 shadow-sm ${mensaje.includes('✅') ? 'alert-success' : 'alert-danger'}`}>
                {mensaje}
              </div>
            )}
          </div>
        </div>

        {/* PANEL DERECHO (CARRITO) */}
        <div className="col-lg-5">
          <div className="card shadow-sm border-0 p-4 bg-white h-100 rounded-4">
            <h5 className="fw-bold text-dark mb-4 border-bottom pb-2">🛒 Detalle de Venta</h5>
            <div className="table-responsive" style={{ minHeight: "250px" }}>
              <table className="table table-sm align-middle">
                <thead>
                  <tr className="text-muted small">
                    <th>Producto</th>
                    <th className="text-center">Cant.</th>
                    <th className="text-end">Total</th>
                    <th></th>
                  </tr>
                </thead>
                <tbody>
                  {carrito.map((p, i) => (
                    <tr key={i}>
                      <td className="small fw-bold">{p.nombre}</td>
                      <td className="text-center">{p.cantidad}</td>
                      <td className="text-end">${(p.cantidad * p.precio).toFixed(2)}</td>
                      <td className="text-end">
                         <button className="btn btn-link text-danger p-0" onClick={() => setCarrito(carrito.filter(item => item.producto_id !== p.producto_id))}>✕</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div className="mt-4 pt-3 border-top">
              <div className="d-flex justify-content-between fs-4 fw-bold text-success">
                <span>TOTAL:</span>
                <span>${(calcularSubtotal() * 1.13).toFixed(2)}</span>
              </div>
              <button
                className="btn btn-success btn-lg w-100 mt-4 shadow-sm fw-bold py-3 rounded-pill"
                onClick={realizarVenta}
                disabled={carrito.length === 0 || loading}
              >
                {loading ? "PROCESANDO..." : "💰 FINALIZAR VENTA"}
              </button>
            </div>
          </div>
        </div>
      </div>

      {ticket && (
        <div className="modal show d-block" style={{ backgroundColor: "rgba(0,0,0,0.5)" }}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 bg-transparent">
               <TicketVenta ticket={ticket} setTicket={setTicket} />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
